#!/usr/bin/env node
// Generates src/data/canonical-pricing.generated.ts from public/pricing-reference.md.
// Run before build so runtime helpers (src/lib/canonical-pricing.ts) have typed data.

import { writeFileSync } from 'node:fs';
import { loadCanonicalPricing } from './lib/canonical-pricing.mjs';

const { skus, ranges, lastUpdated } = loadCanonicalPricing();

const header = `// AUTO-GENERATED by scripts/generate-canonical-pricing.mjs
// Source: public/pricing-reference.md (last_updated: ${lastUpdated})
// Do not edit by hand. Re-run \`npm run generate:canonical-pricing\`.

export interface CanonicalSku {
  partNo: string;
  model: string;
  family: 'FourStroke' | 'ProXS' | 'SeaPro' | 'Verado' | string;
  hp: number;
  dealer: number;
  msrp: number;
  status: string;
  slug: string;
}

export interface CanonicalRange {
  count: number;
  dealerMin: number;
  dealerMax: number;
  msrpMin: number;
  msrpMax: number;
}

export const CANONICAL_LAST_UPDATED = ${JSON.stringify(lastUpdated)};

export const CANONICAL_SKUS: CanonicalSku[] = ${JSON.stringify(skus, null, 2)};

export const CANONICAL_RANGES: Record<string, CanonicalRange | null> = ${JSON.stringify(
  ranges,
  null,
  2,
)};
`;

writeFileSync('src/data/canonical-pricing.generated.ts', header);
console.log(`✓ Generated canonical pricing: ${skus.length} SKUs (last_updated ${lastUpdated})`);
